 1	import React, { FC, useState } from 'react';
 2	
 3	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 4	import DropdownToggle from '@kubevirt-utils/components/toggles/DropdownToggle';
 5	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getContentScrollableElement } from '@kubevirt-utils/utils/utils';
 8	import { Action } from '@openshift-console/dynamic-plugin-sdk';
 9	import {
10	  Divider,
11	  Dropdown,
12	  DropdownGroup,
13	  DropdownItem,
14	  DropdownList,
15	} from '@patternfly/react-core';
16	
17	import { useDataSourceActionsProvider } from '../hooks/useDataSourceActions';
18	
19	import './DataSourceActions.scss';
20	
21	type DataSourceActionProps = {
22	  dataSource: V1beta1DataSource;
23	  isKebabToggle?: boolean;
24	};
25	
26	const DataSourceActions: FC<DataSourceActionProps> = ({ dataSource, isKebabToggle }) => {
27	  const { t } = useKubevirtTranslation();
28	  const [isOpen, setIsOpen] = useState<boolean>(false);
29	  const [actions, onLazyOpen] = useDataSourceActionsProvider(dataSource);
30	
31	  const dsActions = actions.filter((a) => a.id !== 'datasource-action-manage-source');
32	  const manageAction = actions.find((a) => a.id === 'datasource-action-manage-source');
33	
34	  const onToggle = () => {
35	    setIsOpen((prevIsOpen) => {
36	      if (!prevIsOpen) onLazyOpen();
37	
38	      return !prevIsOpen;
39	    });
40	  };
41	
42	  const Toggle = isKebabToggle
43	    ? KebabToggle({ isExpanded: isOpen, onClick: onToggle })
44	    : DropdownToggle({ children: t('Actions'), isExpanded: isOpen, onClick: onToggle });
45	
46	  const handleClick = (action: Action) => {
47	    if (typeof action?.cta === 'function') {
48	      action.cta();
49	    }
50	    setIsOpen(false);
51	  };
52	
53	  return (
54	    <Dropdown
55	      className="kubevirt-data-source-actions"
56	      data-test-id="data-source-actions"
57	      isOpen={isOpen}
58	      onOpenChange={(open: boolean) => setIsOpen(open)}
59	      popperProps={{ appendTo: getContentScrollableElement, position: 'right' }}
60	      toggle={Toggle}
61	    >
62	      <DropdownList>
63	        <DropdownGroup key="datasource-actions" label={t('DataSource')}>
64	          {dsActions?.map((action) => (
65	            <DropdownItem
66	              data-test-id={action?.id}
67	              description={action?.description}
68	              isDisabled={action?.disabled}
69	              key={action?.id}
70	              onClick={() => handleClick(action)}
71	            >
72	              {action?.label}
73	            </DropdownItem>
74	          ))}
75	        </DropdownGroup>
76	        <Divider key="divider" />
77	        <DropdownGroup key="datasource-manage" label={t('DataImportCron')}>
78	          <DropdownItem
79	            data-test-id="datasource-manage"
80	            description={manageAction?.description}
81	            isDisabled={manageAction?.disabled}
82	            key="datasource-manage"
83	            onClick={() => handleClick(manageAction)}
84	          >
85	            {manageAction?.label}
86	          </DropdownItem>
87	        </DropdownGroup>
88	      </DropdownList>
89	    </Dropdown>
90	  );
91	};
92	
93	export default DataSourceActions;

